        })
        output = controller_step(controller, {
            "kind": CONTROLLER_INPUT_LEVEL,
            "temperature_c": 0,
            "level": 70,
            "now_ms": 200,
        })

        # Heat to 46
        output = controller_step(controller, {
            "kind": CONTROLLER_INPUT_NONE,
            "temperature_c": 46,
            "level": 70,
            "now_ms": 300,
        })
        self.assertTrue(output["heater_on"])

        # Now temp rises to 47
        output = controller_step(controller, {
            "kind": CONTROLLER_INPUT_NONE,
            "temperature_c": 47,
            "level": 70,
            "now_ms": 400,
        })
        # Temperature rising (47 > 46), should turn heater off
        self.assertFalse(output["heater_on"])


class TestControllerTimeout(unittest.TestCase):
    """Test that malformed input or stale sensor data forces safe idle."""

    def test_sensor_timeout_forces_safe_idle(self):
        controller = {}
        controller_init(controller)

        # First, get both sensors valid
        output = controller_step(controller, {
            "kind": CONTROLLER_INPUT_TEMPERATURE,
            "temperature_c": 40,
            "level": 0,
            "now_ms": 100,
        })
        output = controller_step(controller, {
            "kind": CONTROLLER_INPUT_LEVEL,
            "temperature_c": 0,
            "level": 70,
            "now_ms": 200,
