        # Heater should be on at safe level with low temp
        output = controller_step(controller, {
            "kind": CONTROLLER_INPUT_NONE,
            "temperature_c": 40,
            "level": 70,
            "now_ms": 300,
        })
        self.assertTrue(output["heater_on"])

        # Now simulate timeout by advancing time more than 1000ms without new sensor data
        output = controller_step(controller, {
            "kind": CONTROLLER_INPUT_NONE,
            "temperature_c": 40,
            "level": 70,
            "now_ms": 1500,  # > 1000ms since last sensor update
        })
        # Should go to safe idle with heater off
        self.assertFalse(output["heater_on"])
        self.assertEqual(output["state"], CONTROLLER_STATE_SAFE_IDLE)


